// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
// Import dữ liệu loài. Bạn cần tạo file này.
import speciesData from '../data/speciesData';

function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farmDetails, setFarmDetails] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State cho form, chỉ chứa các trường cần thiết
  const [formData, setFormData] = useState({
    speciesName: '',      // Tên lâm sản cuối cùng
    scientificName: '',   // Tên khoa học cuối cùng
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  // State để điều khiển giao diện chọn/nhập tay
  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  // Hàm lấy dữ liệu chi tiết của cơ sở và các hoạt động
  const fetchData = useCallback(async () => {
    if (!farmId || !token) {
      setError('Thiếu thông tin xác thực hoặc ID cơ sở.');
      setLoading(false);
      return;
    }
    setLoading(true);
    setError('');
    try {
      // Lấy chi tiết cơ sở
      const farmRes = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFarmDetails(farmRes.data);

      // Lấy danh sách hoạt động
      const activitiesRes = await axios.get(`http://localhost:10000/api/wood-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(activitiesRes.data);

    } catch (err) {
      console.error('Lỗi khi tải dữ liệu:', err);
      setError('Không thể tải dữ liệu.');
    } finally {
      setLoading(false);
    }
  }, [farmId, token]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Hàm xử lý cho các ô input thông thường
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };
  
  // Hàm xử lý riêng cho dropdown "Tên lâm sản"
  const handleSpeciesSelectionChange = (e) => {
    const value = e.target.value;
    setSelectedSpecies(value);

    if (value === 'manual' || value === 'Nhập thủ công') {
      setIsManualEntry(true);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else if (value === '') {
      setIsManualEntry(false);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesData.find(s => s.tenLamSan === value);
      if (matched) {
        setFormData(prev => ({
          ...prev,
          speciesName: matched.tenLamSan,
          scientificName: matched.tenKhoaHoc,
        }));
      }
    }
  };
  
  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      const dataToSend = { ...formData, farm: farmId };
      await axios.post(`http://localhost:10000/api/wood-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });

      fetchData(); // Tải lại danh sách hoạt động sau khi thêm thành công
      setMessage('Thêm bản ghi thành công!');
      
      // Reset form về trạng thái ban đầu
      setFormData({
        speciesName: '', scientificName: '', date: '', quantity: 0, unit: '',
        type: '', reason: '', source: '', destination: '', verifiedBy: '',
      });
      setSelectedSpecies('');
      setIsManualEntry(false);
    } catch (err) {
      setError(err.response?.data?.message || 'Thêm bản ghi thất bại.');
    }
  };

  const handleDeleteActivity = async (activityId) => { /* ... giữ nguyên ... */ };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;
  if (error && !farmDetails) return <div className="form-container error-message"><p>Lỗi: {error}</p></div>;
  
  return (
    <div className="form-container">
      <h2>👁️ Nhật ký hoạt động của cơ sở: {farmDetails?.tenCoSo || 'N/A'}</h2>
      
      <h3>Thêm bản ghi nhập/xuất mới</h3>
      {message && <div className="success-message">{message}</div>}
      
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          
          <div className="form-group-full-width">
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="speciesSelection">Tên lâm sản:</label>
                <select 
                  id="speciesSelection"
                  value={selectedSpecies}
                  onChange={handleSpeciesSelectionChange}
                  required
                >
                  <option value="">-- Chọn hoặc nhập tay --</option>
                  {speciesData.map((species, index) => (
                    <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
                  ))}
                  <option value="manual">--- Nhập tay... ---</option>
                </select>
              </div>

              {!isManualEntry && selectedSpecies && selectedSpecies !== 'manual' && (
                <div className="form-group">
                  <label>Tên khoa học:</label>
                  <input type="text" value={formData.scientificName} readOnly disabled />
                </div>
              )}

              {isManualEntry && (
                <>
                  <div className="form-group">
                    <label htmlFor="speciesName">Tên lâm sản (nhập tay):</label>
                    <input type="text" name="speciesName" value={formData.speciesName} onChange={handleFormChange} required />
                  </div>
                  <div className="form-group">
                    <label htmlFor="scientificName">Tên khoa học (nhập tay):</label>
                    <input type="text" name="scientificName" value={formData.scientificName} onChange={handleFormChange} />
                  </div>
                </>
              )}
            </div>
          </div>
          
          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input type="date" name="date" value={formData.date} onChange={handleFormChange} required />
          </div>
          <div className="form-group">
            <label>Loại giao dịch:</label>
            <select name="type" value={formData.type} onChange={handleFormChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="import">Nhập</option>
              <option value="export">Xuất</option>
            </select>
          </div>
          <div className="form-group">
            <label>Số lượng:</label>
            <input type="number" name="quantity" value={formData.quantity} onChange={handleFormChange} min="0" required />
          </div>
          <div className="form-group">
            <label>Đơn vị:</label>
            <input type="text" name="unit" value={formData.unit} onChange={handleFormChange} required />
          </div>
          <div className="form-group">
            <label>Lý do:</label>
            <input type="text" name="reason" value={formData.reason} onChange={handleFormChange} />
          </div>
          {formData.type === 'import' && (
            <div className="form-group">
              <label>Nguồn gốc:</label>
              <input type="text" name="source" value={formData.source} onChange={handleFormChange} required />
            </div>
          )}
          {formData.type === 'export' && (
            <div className="form-group">
              <label>Nơi đến:</label>
              <input type="text" name="destination" value={formData.destination} onChange={handleFormChange} />
            </div>
          )}
          <div className="form-group">
            <label>Người xác nhận:</label>
            <input type="text" name="verifiedBy" value={formData.verifiedBy} onChange={handleFormChange} />
          </div>
        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      <h3>Lịch sử nhập/xuất gỗ:</h3>
      <div className="activity-list-container">
        {activities.length > 0 ? (
          <table className="activity-table">
            <thead>
              <tr>
                <th>STT</th>
                <th>Ngày</th>
                <th>Tên lâm sản</th>
                <th>Tên khoa học</th>
                <th>Loại</th>
                <th>Số lượng</th>
                <th>Đơn vị</th>
                {role === 'admin' && <th>Hành động</th>}
              </tr>
            </thead>
            <tbody>
              {activities.map((activity, index) => (
                <tr key={activity._id}>
                  <td>{index + 1}</td>
                  <td>{new Date(activity.date).toLocaleDateString()}</td>
                  <td>{activity.speciesName}</td>
                  <td>{activity.scientificName || 'N/A'}</td>
                  <td>{activity.type === 'import' ? 'Nhập' : 'Xuất'}</td>
                  <td>{activity.quantity}</td>
                  <td>{activity.unit}</td>
                  {role === 'admin' && (
                    <td>
                      <button onClick={() => handleDeleteActivity(activity._id)} className="delete-button">Xóa</button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p>Chưa có hoạt động nào được ghi nhận.</p>
        )}
      </div>

      <div className="detail-actions">
        <button onClick={() => navigate('/admin/woods')} className="cancel-button">Quay lại danh sách</button>
      </div>
    </div>
  );
}

export default WoodDetail;
